// 

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import './Navbar.css';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      const offset = window.scrollY;
      if (offset > 50) {
        setScrolled(true);
      } else {
        setScrolled(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => {
      window.addEventListener('scroll', handleScroll);
    };
  }, []);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
    if (!isMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
  };

  const closeMenu = () => {
    setIsMenuOpen(false);
    document.body.style.overflow = 'unset';
  };

  const isActive = (path) => {
    return location.pathname === path;
  };

  return (
    <nav className={`navbar ${scrolled ? 'navbar-scrolled' : ''}`}>
      <div className="container">
        <div className="navbar-content">
          <Link to="/" className="navbar-brand" onClick={closeMenu}>
            <div className="brand-icon">
              <svg width="40" height="40" viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg">
                <rect x="8" y="12" width="24" height="20" rx="2" stroke="currentColor" strokeWidth="2"/>
                <path d="M8 20L32 20" stroke="currentColor" strokeWidth="2"/>
                <circle cx="20" cy="22" r="3" fill="currentColor"/>
                <path d="M14 32L26 32" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
              </svg>
            </div>
            <div className="brand-text-wrapper">
              <span className="brand-text">SMCS</span>
              <span className="brand-subtitle">Shree Moolpuri Construction & Supplier</span>
            </div>
          </Link>

          <button 
            className={`navbar-toggle ${isMenuOpen ? 'active' : ''}`}
            onClick={toggleMenu}
            aria-label="Toggle navigation"
          >
            <span></span>
            <span></span>
            <span></span>
          </button>

          <div className={`navbar-overlay ${isMenuOpen ? 'active' : ''}`} onClick={closeMenu}></div>

          <ul className={`navbar-nav ${isMenuOpen ? 'active' : ''}`}>
            <li className="nav-item">
              <Link 
                to="/" 
                className={`nav-link ${isActive('/') ? 'active' : ''}`}
                onClick={closeMenu}
              >
                <span className="nav-link-text">Home</span>
                {isActive('/') && <span className="nav-indicator"></span>}
              </Link>
            </li>
            <li className="nav-item">
              <Link 
                to="/about" 
                className={`nav-link ${isActive('/about') ? 'active' : ''}`}
                onClick={closeMenu}
              >
                <span className="nav-link-text">About</span>
                {isActive('/about') && <span className="nav-indicator"></span>}
              </Link>
            </li>
            <li className="nav-item">
              <Link 
                to="/projects" 
                className={`nav-link ${isActive('/projects') ? 'active' : ''}`}
                onClick={closeMenu}
              >
                <span className="nav-link-text">Projects</span>
                {isActive('/projects') && <span className="nav-indicator"></span>}
              </Link>
            </li>
            <li className="nav-item">
              <Link 
                to="/partnerships" 
                className={`nav-link ${isActive('/partnerships') ? 'active' : ''}`}
                onClick={closeMenu}
              >
                <span className="nav-link-text">Partnerships</span>
                {isActive('/partnerships') && <span className="nav-indicator"></span>}
              </Link>
            </li>
            <li className="nav-item">
              <Link 
                to="/public-contracts" 
                className={`nav-link ${isActive('/public-contracts') ? 'active' : ''}`}
                onClick={closeMenu}
              >
                <span className="nav-link-text">Public Contracts</span>
                {isActive('/public-contracts') && <span className="nav-indicator"></span>}
              </Link>
            </li>
            <li className="nav-item">
              <Link 
                to="/contact" 
                className={`nav-link ${isActive('/contact') ? 'active' : ''}`}
                onClick={closeMenu}
              >
                <span className="nav-link-text">Contact</span>
                {isActive('/contact') && <span className="nav-indicator"></span>}
              </Link>
            </li>
          </ul>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
